mapper.update:
UPDATE ow_member
   SET status = 'WITHDRAWN', withdraw_at = SYSDATE
 WHERE id = #{id}

mapper.delete:
BEGIN
  DELETE FROM ow_board_vote   WHERE member_id   = #{id};
  DELETE FROM ow_comment_vote WHERE member_id   = #{id};
  DELETE FROM ow_report       WHERE reporter_id = #{id};
  DELETE FROM ow_message      WHERE sender_id   = #{id} OR receiver_id = #{id};
  DELETE FROM ow_notification WHERE user_id     = #{id};
  DELETE FROM ow_party        WHERE writer_id   = #{id};
  DELETE FROM ow_comment      WHERE writer_id   = #{id};
  DELETE FROM ow_board        WHERE writer_id   = #{id};
  DELETE FROM ow_member       WHERE id          = #{id};
END;

mapper.select:
SELECT CASE WHEN nickname_changed IS NULL OR nickname_changed + 30 <= SYSDATE
            THEN 1 ELSE 0 END
  FROM ow_member WHERE id = #{id}
